const express = require('express');
const bodyParser = require('body-parser');

const app = express();
const PORT = process.env.PORT || 3000;

// Middleware to parse JSON request bodies
app.use(bodyParser.json());

// --- Simulated Database (In-memory for demonstration) ---
// In a real application, this would be a persistent database (e.g., MongoDB, PostgreSQL)

// Stores user data including currency and level progress
const users = {
    // Example user
    'user123': {
        coins: 100,
        gems: 10,
        levelProgress: {
            // 'levelId': { highestScore: number, bestTime: number, lastCompleted: Date }
            'level1': { highestScore: 0, bestTime: Infinity, lastCompleted: null },
            'level2': { highestScore: 0, bestTime: Infinity, lastCompleted: null }
        }
    },
    'user456': {
        coins: 50,
        gems: 5,
        levelProgress: {}
    }
};

// Defines rewards and criteria for each level
const levelDefinitions = {
    'level1': {
        baseCoins: 50,          // Coins awarded just for completing
        bonusCoinsThreshold: 100, // Score needed for bonus coins
        bonusCoinsAmount: 20,
        bonusGemsThreshold: 60,   // Time (seconds) needed for bonus gems (lower is better)
        bonusGemsAmount: 5,
        completionLimit: 1        // How many times a player can claim rewards for this level (0 for unlimited, 1 for once)
    },
    'level2': {
        baseCoins: 75,
        bonusCoinsThreshold: 150,
        bonusCoinsAmount: 30,
        bonusGemsThreshold: 90,
        bonusGemsAmount: 7,
        completionLimit: 0
    },
    'level3': {
        baseCoins: 100,
        bonusCoinsThreshold: 200,
        bonusCoinsAmount: 40,
        bonusGemsThreshold: 120,
        bonusGemsAmount: 10,
        completionLimit: 1
    }
};

// --- Helper Functions ---

/**
 * Calculates rewards based on level metrics.
 * @param {string} levelId - The ID of the completed level.
 * @param {number} score - The score achieved.
 * @param {number} time - The time taken in seconds.
 * @returns {object} - An object containing awarded coins and gems.
 */
function calculateRewards(levelId, score, time) {
    const levelDef = levelDefinitions[levelId];
    if (!levelDef) {
        return { coins: 0, gems: 0 };
    }

    let awardedCoins = levelDef.baseCoins;
    let awardedGems = 0;

    if (score >= levelDef.bonusCoinsThreshold) {
        awardedCoins += levelDef.bonusCoinsAmount;
    }
    if (time <= levelDef.bonusGemsThreshold) {
        awardedGems += levelDef.bonusGemsAmount;
    }

    return { coins: awardedCoins, gems: awardedGems };
}

// --- API Endpoints ---

/**
 * POST /api/levels/complete
 * Endpoint for completing a level and claiming rewards.
 * Requires: userId, levelId, score, time
 */
app.post('/api/levels/complete', (req, res) => {
    const { userId, levelId, score, time } = req.body;

    // 1. Input Validation
    if (!userId || !levelId || typeof score !== 'number' || typeof time !== 'number' || score < 0 || time < 0) {
        return res.status(400).json({ message: 'Invalid request data. Please provide userId, levelId, score (>=0), and time (>=0).' });
    }

    const user = users[userId];
    const levelDef = levelDefinitions[levelId];

    if (!user) {
        return res.status(404).json({ message: 'User not found.' });
    }
    if (!levelDef) {
        return res.status(404).json({ message: 'Level definition not found.' });
    }

    // Initialize level progress for user if not exists
    if (!user.levelProgress[levelId]) {
        user.levelProgress[levelId] = { highestScore: 0, bestTime: Infinity, lastCompleted: null, completionCount: 0 };
    }
    const userLevelProgress = user.levelProgress[levelId];

    // 2. Check Completion Limit
    if (levelDef.completionLimit > 0 && userLevelProgress.completionCount >= levelDef.completionLimit) {
        // If the user has already claimed rewards for this level the maximum allowed times
        return res.status(200).json({
            message: `Level ${levelId} completed, but rewards for this level have already been claimed ${levelDef.completionLimit} time(s).`,
            levelId,
            userId,
            awardedRewards: { coins: 0, gems: 0 },
            currentTotalRewards: { coins: user.coins, gems: user.gems }
        });
    }

    // 3. Update User Level Progress (always update best score/time regardless of reward claim)
    let isNewBestScore = false;
    let isNewBestTime = false;

    if (score > userLevelProgress.highestScore) {
        userLevelProgress.highestScore = score;
        isNewBestScore = true;
    }
    if (time < userLevelProgress.bestTime) {
        userLevelProgress.bestTime = time;
        isNewBestTime = true;
    }
    userLevelProgress.lastCompleted = new Date();

    // 4. Calculate and Award Rewards
    const awarded = calculateRewards(levelId, score, time);

    user.coins += awarded.coins;
    user.gems += awarded.gems;
    userLevelProgress.completionCount++; // Increment completion count for this level

    // 5. Send Response
    return res.status(200).json({
        message: 'Level completed and rewards claimed successfully!',
        levelId,
        userId,
        awardedRewards: awarded,
        currentTotalRewards: { coins: user.coins, gems: user.gems },
        levelProgressUpdate: {
            highestScore: userLevelProgress.highestScore,
            bestTime: userLevelProgress.bestTime,
            isNewBestScore,
            isNewBestTime
        }
    });
});

/**
 * GET /api/users/:userId/rewards
 * Endpoint to check a user's current total rewards.
 */
app.get('/api/users/:userId/rewards', (req, res) => {
    const { userId } = req.params;
    const user = users[userId];

    if (!user) {
        return res.status(404).json({ message: 'User not found.' });
    }

    res.status(200).json({
        userId,
        coins: user.coins,
        gems: user.gems
    });
});

/**
 * GET /api/users/:userId/progress
 * Endpoint to check a user's overall level progress.
 */
app.get('/api/users/:userId/progress', (req, res) => {
    const { userId } = req.params;
    const user = users[userId];

    if (!user) {
        return res.status(404).json({ message: 'User not found.' });
    }

    res.status(200).json({
        userId,
        levelProgress: user.levelProgress
    });
});


// --- Server Start ---
app.listen(PORT, () => {
    console.log(`Mobile Game API running on port ${PORT}`);
    console.log('Available Endpoints:');
    console.log(`  POST /api/levels/complete`);
    console.log(`  GET /api/users/:userId/rewards`);
    console.log(`  GET /api/users/:userId/progress`);
});

